export type MessageKey = keyof typeof messageCatalog
export type Messages = Record<MessageKey, string>

function buildMessages(language: MessageLanguage): Messages {
  return Object.fromEntries(
    Object.entries(messageCatalog).map(([key, translations]) => [key, translations[language]])
  ) as Messages
}

export const enMessages = buildMessages('en')
export const messages = Object.fromEntries(
  messageLanguages.map((language) => [language, buildMessages(language)])
) as Record<MessageLanguage, Messages>
